import{_ as o,c as a,o as l,ag as i}from"./chunks/framework.DVUBUV_u.js";const u=JSON.parse('{"title":"Релиз 2.2.0","description":"","frontmatter":{"title":"Релиз 2.2.0"},"headers":[],"relativePath":"releases/2.2.0.md","filePath":"releases/2.2.0.md"}'),d={name:"releases/2.2.0.md"};function c(r,e,t,n,s,p){return l(),a("div",null,[...e[0]||(e[0]=[i('<h2 id="_2-2-0-2026-02-24" tabindex="-1">[2.2.0] - 2026-02-24 <a class="header-anchor" href="#_2-2-0-2026-02-24" aria-label="Permalink to &quot;[2.2.0] - 2026-02-24&quot;">​</a></h2><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li><p>Добавлена настройка <code>Display Mode</code> с возможностью переноса приложения во вкладку <code>DevTools</code> и отключения <code>overlay</code>-режима.</p></li><li><p>Проведён рефакторинг вкладки <code>Options</code> — настройки разбиты на логические разделы.</p></li><li><p>Изменена логика работы активных фильтров на вкладках <code>Props</code>, <code>Pinia Store</code> и <code>Network</code>: редактирование набора фильтров теперь доступно без перехода в настройки.</p></li><li><p>Исправлена область нажатия (<code>click area</code>) в текстовом режиме отображения <code>JSON</code>.</p></li><li><p>Большие <code>JSON</code> больше не обрезаются: для сохранения производительности при отображении отключаются CSS-стили.</p></li><li><p>Обновлена логика уведомления о новых версиях:</p><ul><li><code>Dismiss</code> переименована в <code>Later</code>;</li><li><code>Download</code> переименована в <code>Preview</code> и ведёт в <code>Options → About</code>;</li><li>добавлен блок с деталями версии и кнопками <code>Ignore</code> и <code>Download</code>.</li></ul></li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Исправлена ошибка отсутствия подсветки UI-элементов <code>Props</code> в режиме <code>Standalone</code>.</li></ul><hr><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li><p>Добавлена поддержка <code>form-data</code> для чтения и подмены трафика.</p></li><li><p>Добавлена возможность сохранять используемые файлы для повторного использования при работе с <code>Breakpoint</code> и <code>form-data</code>.</p></li><li><p>Добавлены режимы <code>Rewrite Breakpoint</code> и <code>Rewrite Mock</code>: при наличии существующего перехвата предлагается перезаписать правило вместо создания нового.</p></li><li><p>Добавлена индикация активных <code>Breakpoint</code> и <code>Mock</code> для запроса; переход по счётчику открывает соответствующий раздел настроек.</p></li><li><p>Добавлен поиск по статус-коду ответа.</p></li><li><p>Расширены возможности <code>Breakpoint</code> — добавлен учёт HTTP-метода при перехвате.</p></li><li><p>Исправлена ошибка, при которой инспектор не открывался при срабатывании <code>Breakpoint</code>.</p></li><li><p>В контекстное меню запроса добавлены действия:</p><ul><li><code>Disable / Enable Breakpoint</code></li><li><code>Disable / Enable Mock</code></li><li><code>Delete Breakpoint / Mock</code></li><li>пункты отображаются только при наличии соответствующего правила.</li></ul></li></ul><hr><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><h4 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h4><ul><li>Базовые настройки приложения (<code>Display Mode</code>, <code>Search Parameters</code>, <code>Auto Refresh</code>, <code>JSON Editor Mode</code>) перенесены в отдельный раздел.</li><li>Управление файлом настроек (<code>Settings Management</code>) перенесено из шапки вкладки.</li></ul><h4 id="network-1" tabindex="-1">Network <a class="header-anchor" href="#network-1" aria-label="Permalink to &quot;Network&quot;">​</a></h4><ul><li><code>Search Settings</code> вынесены в отдельный раздел и стали независимыми.</li><li>Скорректирована вёрстка таблиц <code>Breakpoints</code> и <code>Mocks</code> — данные больше не растягиваются.</li><li>Добавлена возможность отключения и редактирования ранее созданных правил.</li></ul><h4 id="props-1" tabindex="-1">Props <a class="header-anchor" href="#props-1" aria-label="Permalink to &quot;Props&quot;">​</a></h4><ul><li>Управление файлом настроек перенесено в раздел.</li><li><code>Component Blacklist</code> перенесён из общего блока настроек.</li><li><code>Favorite Components</code> перенесены из общего блока настроек.</li></ul><h4 id="pinia-store" tabindex="-1">Pinia Store <a class="header-anchor" href="#pinia-store" aria-label="Permalink to &quot;Pinia Store&quot;">​</a></h4><ul><li>Управление файлом настроек перенесено в раздел.</li></ul><h4 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h4><ul><li><p>Добавлены кнопки <code>Release notes</code> и <code>Check for updates</code> (доступно только в <code>extension</code>-версии).</p></li><li><p>При наличии новой версии:</p><ul><li><code>Ignore</code> отключает повторные уведомления для текущей версии; состояние сбрасывается после выхода более новой версии.</li><li><code>Download</code> инициирует загрузку архива с приложением.</li></ul></li></ul>',21)])])}const k=o(d,[["render",c]]);export{u as __pageData,k as default};
